// Generated by Spec-to-RTL pipeline: grammar -> IR -> RTL
// Repair demo setup: injected a shift-register bug that reverses the declared shift direction

module shift_left4 (
    input clk,
    input rst_n,
    input en,
    input serial_in,
    output reg [3:0] shreg
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            shreg <= 4'd0;
        end else begin
            if (en) begin
                shreg <= {serial_in, shreg[3:1]};
            end
        end
    end

endmodule
